network = {
    "Ada": ["Ben", "Cora"],
    "Ben": ["Ada", "Dev"],
    "Cora": ["Ada", "Eli"],
    "Dev": ["Ben"],
    "Eli": ["Cora"],
}

def can_reach(start, target, visited):
    if start == target:
        return True
    visited.append(start)
    for neighbor in network[start]:
        if neighbor not in visited:
            if can_reach(neighbor, target, visited):
                return True
    return False

print(can_reach("Ada", "Eli", []))
print(can_reach("Dev", "Eli", []))
